import type { ChartUnit } from '../../core/types/chart-unit.js';
import type { HistogramSeries } from '../../histogram/types/histogram.js';
import type { XYChartData } from '../../xy-chart/types/xy-chart.js';

export interface SeriesColor {
  name: string;
  color: string;
}
interface TransformHistogramDataResult {
  barSeriesProps: BarSeriesProps[];
  units: Set<ChartUnit>;
  seriesColors: SeriesColor[];
}

type BarSeriesProps = {
  data: XYChartData[];
  unit: ChartUnit;
  seriesCount: number;
};

export function transformHistogramDataToXYChart(
  data: HistogramSeries[],
): TransformHistogramDataResult {
  const seriesColors: SeriesColor[] = [];
  const units: Set<ChartUnit> = new Set();
  const unitToData = new Map<ChartUnit, XYChartData[]>();
  const unitToSeriesCount = new Map<ChartUnit, number>();

  data.forEach((series, index) => {
    const { bins, name, color, unit, ...extraSeriesProps } =
      series as HistogramSeries & Record<string, unknown>;

    if (color) {
      seriesColors.push({ name, color });
    }

    const binData = bins.map((bin) => ({
      ...extraSeriesProps,
      x0: bin.from,
      x1: bin.to,
      y1: bin.value,
      name,
      seriesId: index.toString(),
    }));

    unitToData.set(unit, [...(unitToData.get(unit) ?? []), ...binData]);
    unitToSeriesCount.set(unit, (unitToSeriesCount.get(unit) ?? 0) + 1);
    units.add(unit);
  });

  return {
    barSeriesProps: Array.from(unitToData, ([unit, data]) => ({
      unit,
      data,
      seriesCount: unitToSeriesCount.get(unit) ?? 1,
    })),
    units,
    seriesColors,
  };
}
